CREATE TABLE ledger_hold (hold_id UUID PRIMARY KEY, ledger_account_id UUID NOT NULL REFERENCES ledger_account(ledger_account_id), currency CHAR(3) NOT NULL, minor_units BIGINT NOT NULL CHECK(minor_units > 0), status VARCHAR(16) NOT NULL, idempotency_key TEXT NOT NULL UNIQUE, created_at TIMESTAMPTZ NOT NULL, expires_at TIMESTAMPTZ NOT NULL CHECK(expires_at > created_at));
CREATE TABLE ledger_release (release_id UUID PRIMARY KEY, hold_id UUID NOT NULL REFERENCES ledger_hold(hold_id), reason_code TEXT NOT NULL, idempotency_key TEXT NOT NULL UNIQUE, released_at TIMESTAMPTZ NOT NULL);
